const text = $input.first().json.text || '';

const wordCount = text.split(/\s+/).filter(w => w.length > 0).length;
const hasNumbers = /\d/.test(text);
const hasLetters = /[a-zA-Z]/.test(text);
const specialCharCount = (text.match(/[^a-zA-Z0-9\s.,;:$#@!?()\-\/]/g) || []).length;
const specialCharRatio = text.length > 0 ? specialCharCount / text.length : 0;

let quality = 'high';
let errors = [];

if (wordCount < 10) {
  quality = 'low';
  errors.push('Too few words extracted (possible scan quality issue)');
}

if (!hasNumbers || !hasLetters) {
  quality = 'low';
  errors.push('Missing expected content (numbers or letters)');
}

if (specialCharRatio > 0.3) {
  quality = 'low';
  errors.push('High special character ratio (OCR artifacts)');
}

if (quality !== 'low' && !text.toLowerCase().includes('invoice') && !text.toLowerCase().includes('total') && !text.toLowerCase().includes('amount')) {
  quality = 'medium';
  errors.push('Expected invoice keywords missing - may not be an invoice document');
}

return [{
  json: {
    data: text,
    ocr_quality: quality,
    ocr_errors: errors,
    is_valid: quality !== 'low',
    word_count: wordCount
  }
}];

