const subject = $input.first().json.subject || '';

const monthNames = ['january', 'february', 'march', 'april', 'may', 'june',
                    'july', 'august', 'september', 'october', 'november', 'december'];

let month = null;
let year = new Date().getFullYear();

const yearMatch = subject.match(/\b(20\d{2})\b/);
if (yearMatch) year = parseInt(yearMatch[1]);

const subjectLower = subject.toLowerCase();
for (let i = 0; i < monthNames.length; i++) {
  if (subjectLower.includes(monthNames[i])) {
    month = String(i + 1).padStart(2, '0');
    break;
  }
}

if (!month) {
  const lastMonth = new Date();
  lastMonth.setMonth(lastMonth.getMonth() - 1);
  month = String(lastMonth.getMonth() + 1).padStart(2, '0');
  year = lastMonth.getFullYear();
}

const analysisMonth = `${year}-${month}`;

return [{
  json: {
    analysisMonth,
    requestedBy: $input.first().json.from.value[0].address
  }
}];

const invoices = $('Read Invoices from Sheets').all();
const sales = $('Read Sales from Sheets').all();
const month = $('Extract Month from Email').item.json.analysisMonth;

let totalSupplyCost = 0;
const allSupplyItems = [];

invoices.forEach(inv => {
  if (inv.json.month === month) {
    totalSupplyCost += parseFloat(inv.json.total_cost || 0);
    try {
      const items = JSON.parse(inv.json.items || '[]');
      allSupplyItems.push(...items);
    } catch(e) {}
  }
});

let totalRevenue = 0;
const allSalesItems = [];

sales.forEach(sale => {
  if (sale.json.month === month) {
    totalRevenue += parseFloat(sale.json.total_revenue || 0);
    try {
      const items = JSON.parse(sale.json.items || '[]');
      allSalesItems.push(...items);
    } catch(e) {}
  }
});

const supplyMap = {};
allSupplyItems.forEach(item => {
  const key = (item.name || '').toLowerCase().trim();
  if (!key) return;
  if (!supplyMap[key]) supplyMap[key] = {name: item.name, qty: 0, totalCost: 0};
  supplyMap[key].qty += (item.qty || 0);
  supplyMap[key].totalCost += (item.total_cost || 0);
});

const salesMap = {};
allSalesItems.forEach(item => {
  const key = (item.name || '').toLowerCase().trim();
  if (!key) return;
  if (!salesMap[key]) salesMap[key] = {name: item.name, qty: 0, totalRevenue: 0};
  salesMap[key].qty += (item.qty || 0);
  salesMap[key].totalRevenue += (item.total_revenue || 0);
});

return [{
  json: {
    analysisMonth: month,
    invoiceCount: invoices.filter(i => i.json.month === month).length,
    salesReportCount: sales.filter(s => s.json.month === month).length,
    supplyData: JSON.stringify(Object.values(supplyMap)),
    salesData: JSON.stringify(Object.values(salesMap)),
    totalSupplyCost,
    totalRevenue
  }
}];

const analysis = $input.first().json;
const aggData = $('Aggregate Data').item.json;

const month = analysis.analysisMonth || aggData.analysisMonth;
const [year, monthNum] = month.split('-');
const monthNames = ['January','February','March','April','May','June','July','August','September','October','November','December'];
const displayMonth = `${monthNames[parseInt(monthNum)-1]} ${year}`;

// Parse JSON strings back to arrays for the Report Writer
const itemBreakdown = JSON.parse(analysis.itemBreakdown || '[]');
const topSellers = JSON.parse(analysis.topSellers || '[]');
const fastMovers = JSON.parse(analysis.fastMovers || '[]');
const deadStock = JSON.parse(analysis.deadStock || '[]');
const reorderRecommendations = JSON.parse(analysis.reorderRecommendations || '[]');
const alerts = JSON.parse(analysis.alerts || '[]');

return [{
  json: {
    stationName: 'Gas Station',
    analysisMonth: displayMonth,
    invoiceCount: aggData.invoiceCount,
    salesReportCount: aggData.salesReportCount,
    totalSupplyCost: analysis.totalSupplyCost,
    totalRevenue: analysis.totalRevenue,
    grossProfit: analysis.grossProfit,
    profitMarginPct: analysis.profitMarginPct,
    itemBreakdown: itemBreakdown,
    topSellers: topSellers,
    fastMovers: fastMovers,
    deadStock: deadStock,
    reorderRecommendations: reorderRecommendations,
    alerts: alerts
  }
}];

const text = $input.first().json.output || '';
try {
  const jsonMatch = text.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    const parsed = JSON.parse(jsonMatch[0]);
    return [{
      json: {
        vendor: parsed.vendor || '',
        invoice_date: parsed.invoice_date || '',
        month: parsed.month || '',
        items: JSON.stringify(parsed.items || []),
        total_cost: parsed.total_cost || 0
      }
    }];
  }
} catch(e) {}
return [{ json: { error: 'Could not parse invoice JSON', raw: text.substring(0, 500) } }];

const text = $input.first().json.output || '';
try {
  const jsonMatch = text.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    const parsed = JSON.parse(jsonMatch[0]);
    return [{
      json: {
        report_date: parsed.report_date || '',
        month: parsed.month || '',
        items: JSON.stringify(parsed.items || []),
        total_revenue: parsed.total_revenue || 0
      }
    }];
  }
} catch(e) {}
return [{ json: { error: 'Could not parse sales JSON', raw: text.substring(0, 500) } }];

const text = $input.first().json.output || '';
let parsed;
try {
  const jsonMatch = text.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    parsed = JSON.parse(jsonMatch[0]);
  } else {
    return [{ json: { error: 'No JSON found', raw: text.substring(0, 500) } }];
  }
} catch(e) {
  return [{ json: { error: 'JSON parse failed', raw: text.substring(0, 500) } }];
}

const items = parsed.itemBreakdown || [];
const grossProfit = parsed.grossProfit || (parsed.totalRevenue - parsed.totalSupplyCost);

// Top sellers by revenue
const topSellers = [...items]
  .sort((a, b) => b.revenue - a.revenue)
  .slice(0, 5)
  .map(i => ({ name: i.name, qtySold: i.qtySold, revenue: i.revenue, sellThroughPct: i.sellThroughPct }));

// Fast movers: >60% sell-through
const fastMovers = items
  .filter(i => i.sellThroughPct > 60)
  .map(i => ({ name: i.name, sellThroughPct: i.sellThroughPct, note: 'reorder soon' }));

// Dead stock: <20% sell-through
const deadStock = items
  .filter(i => i.sellThroughPct < 20)
  .map(i => ({ name: i.name, qtySupplied: i.qtySupplied, qtySold: i.qtySold, sellThroughPct: i.sellThroughPct }));

// Slow movers: 20-40%
const slowMovers = items.filter(i => i.sellThroughPct >= 20 && i.sellThroughPct < 40);

// Reorder recommendations with context
const reorderRecommendations = [];
if (fastMovers.length > 0) {
  fastMovers.forEach(i => {
    const item = items.find(x => x.name === i.name);
    const remaining = item.qtySupplied - item.qtySold;
    reorderRecommendations.push(`${i.name}: ${i.sellThroughPct}% sold through with ${remaining} units remaining. High demand - reorder before stock runs out.`);
  });
} else {
  // Show top 3 best performers even if none hit 60%
  const best = [...items].sort((a, b) => b.sellThroughPct - a.sellThroughPct).slice(0, 3);
  best.forEach(i => {
    const remaining = i.qtySupplied - i.qtySold;
    reorderRecommendations.push(`${i.name}: Best sell-through at ${i.sellThroughPct}% (${i.qtySold} sold, ${remaining} remaining). Monitor as month progresses.`);
  });
}
if (deadStock.length > 0) {
  deadStock.forEach(i => {
    reorderRecommendations.push(`${i.name}: Only ${i.sellThroughPct}% sold (${i.qtySold} of ${i.qtySupplied} units). Consider reducing next order quantity.`);
  });
}

// Alerts - actionable only, no redundant margin summary
const alerts = [];
if (deadStock.length > 0) {
  deadStock.forEach(i => {
    alerts.push(`Dead stock: ${i.name} - only ${i.qtySold} of ${i.qtySupplied} units sold (${i.sellThroughPct}%). Risk of expiry or waste.`);
  });
}
if (slowMovers.length > 0) {
  alerts.push(`Slow movers this period: ${slowMovers.map(i => i.name).join(', ')} - all between 20-40% sell-through. Review pricing or placement.`);
}
const zeroSales = items.filter(i => i.qtySold === 0);
if (zeroSales.length > 0) {
  alerts.push(`No sales recorded for: ${zeroSales.map(i => i.name).join(', ')}. Verify stock placement and visibility.`);
}
if (alerts.length === 0) {
  alerts.push('All items are selling. No dead stock or zero-sale items detected this period.');
}

return [{
  json: {
    analysisMonth: parsed.analysisMonth || '',
    totalSupplyCost: parsed.totalSupplyCost || 0,
    totalRevenue: parsed.totalRevenue || 0,
    grossProfit: grossProfit,
    profitMarginPct: parsed.profitMarginPct || 0,
    itemBreakdown: JSON.stringify(items),
    topSellers: JSON.stringify(topSellers),
    fastMovers: JSON.stringify(fastMovers),
    deadStock: JSON.stringify(deadStock),
    reorderRecommendations: JSON.stringify(reorderRecommendations),
    alerts: JSON.stringify(alerts)
  }
}];

